import Dimensions from"../Dimensions";export default class PixelRatio{static get(){return Dimensions.get("window").scale}static getFontScale(){return Dimensions.get("window").fontScale||PixelRatio.get()}static getPixelSizeForLayoutSize(t){return Math.round(t*PixelRatio.get())}static roundToNearestPixel(t){var e=PixelRatio.get();return Math.round(t*e)/e}}